#nullable enable // autogenerated

using MVZ2.Vanilla.Level;

using MVZ2Logic.Callbacks;
using MVZ2Logic.Level;
using MVZ2Logic.Modding;

using PVZEngine.Callbacks;
using PVZEngine.Level;

using UnityEngine;

namespace MVZ2.GameContent.GlobalCallbacks
{
    [ModGlobalCallbacks]
    public class SpawnGlobalCallbacks : VanillaGlobalCallbacks
    {
        public override void Apply(Mod mod)
        {
            mod.AddTrigger(LogicLevelCallbacks.CALCULATE_SPAWN_POINTS, CalculateSpawnPointsCallback);
        }
        private void CalculateSpawnPointsCallback(LogicLevelCallbacks.CalculateSpawnPointParams param, CallbackResult result)
        {
            var level = param.level;
            var wave = param.wave;
            var flags = param.flags;
            var output = param.param;

            var isBossFight = level.WaveState == VanillaLevelStates.STATE_BOSS_FIGHT || level.WaveState == VanillaLevelStates.STATE_BOSS_FIGHT_2;
            if (isBossFight)
            {
                var totalWave = level.GetTotalFlags() * level.GetWavesPerFlag();
                output.basePoints = Mathf.FloorToInt(totalWave * 0.8f) / 2 + 1;
                output.multiplier = level.GetBossSpawnPointMultiplier();
            }
            else
            {
                var totalWave = level.GetLevelTotalWaves(wave, flags);
                output.basePoints = Mathf.FloorToInt(totalWave * 0.8f) / 2 + 1;
                if (level.IsHugeWave(wave) && (level.WaveState == VanillaLevelStates.STATE_STARTED || level.WaveState == VanillaLevelStates.STATE_FINAL_WAVE))
                {
                    output.multiplier *= 2.5f;
                }
            }
        }
    }
}